SELECT canonical.grouping_id, canonical.event_month, canonical.lag_day, canonical.load_epoch_day, canonical.batch_id, canonical.alt_value, canonical.row_count, canonical.n_curve_eligible, canonical.n_null_event_time, canonical.n_null_load_time_only, canonical.n_negative_clipped, canonical.n_negative_lag_excluded, canonical.n_overflow, canonical.n_join_unmatched, canonical.n_other_exclusions, canonical.n_base_rows, canonical.n_ambiguous_base_rows, canonical.max_lookup_dup, canonical.distinct_keys, canonical.min_load_time 
FROM (SELECT grouping(mp_probe.event_month) * $1 + grouping(mp_probe.lag_day) * $2 + grouping(mp_probe.load_epoch_day) * $3 + grouping(mp_probe.batch_id) * $4 + grouping(mp_probe.alt_value) * $5 AS grouping_id, mp_probe.event_month AS event_month, mp_probe.lag_day AS lag_day, mp_probe.load_epoch_day AS load_epoch_day, mp_probe.batch_id AS batch_id, mp_probe.alt_value AS alt_value, count(*) AS row_count, coalesce(sum(mp_probe.is_eligible), $6) AS n_curve_eligible, coalesce(sum(mp_probe.is_null_event_time), $7) AS n_null_event_time, coalesce(sum(mp_probe.is_null_load_time_only), $8) AS n_null_load_time_only, coalesce(sum(mp_probe.is_negative_clipped), $9) AS n_negative_clipped, coalesce(sum(mp_probe.is_negative_lag_excluded), $10) AS n_negative_lag_excluded, coalesce(sum(mp_probe.is_overflow), $11) AS n_overflow, coalesce(sum(mp_probe.is_join_unmatched), $12) AS n_join_unmatched, CAST($13 AS BIGINT) AS n_other_exclusions, coalesce(sum(mp_probe.is_base_row), $14) AS n_base_rows, coalesce(sum(mp_probe.is_ambiguous_base), $15) AS n_ambiguous_base_rows, max(mp_probe.lookup_dup) AS max_lookup_dup, CAST(NULL AS BIGINT) AS distinct_keys, min(mp_probe.load_time) AS min_load_time 
FROM mp_probe GROUP BY GROUPING SETS ((mp_probe.event_month, mp_probe.lag_day), (mp_probe.load_epoch_day), (mp_probe.event_month, mp_probe.batch_id), (mp_probe.alt_value)) UNION ALL SELECT $16 AS grouping_id, CAST(NULL AS DATE) AS event_month, CAST(NULL AS INTEGER) AS lag_day, CAST(NULL AS DATE) AS load_epoch_day, CAST(NULL AS VARCHAR) AS batch_id, CAST(NULL AS VARCHAR) AS alt_value, count(*) AS row_count, coalesce(sum(mp_probe.is_eligible), $17) AS n_curve_eligible, coalesce(sum(mp_probe.is_null_event_time), $18) AS n_null_event_time, coalesce(sum(mp_probe.is_null_load_time_only), $19) AS n_null_load_time_only, coalesce(sum(mp_probe.is_negative_clipped), $20) AS n_negative_clipped, coalesce(sum(mp_probe.is_negative_lag_excluded), $21) AS n_negative_lag_excluded, coalesce(sum(mp_probe.is_overflow), $22) AS n_overflow, coalesce(sum(mp_probe.is_join_unmatched), $23) AS n_join_unmatched, CAST($24 AS BIGINT) AS n_other_exclusions, coalesce(sum(mp_probe.is_base_row), $25) AS n_base_rows, coalesce(sum(mp_probe.is_ambiguous_base), $26) AS n_ambiguous_base_rows, max(mp_probe.lookup_dup) AS max_lookup_dup, count(DISTINCT mp_probe.key_hash) AS distinct_keys, min(mp_probe.load_time) AS min_load_time 
FROM mp_probe) AS canonical ORDER BY canonical.grouping_id 
 LIMIT $27
